import React, { useState } from 'react';
import './CartPage.css';

const CartPage = ({
    cart,
    removeFromCart,
    updateCartQuantity,
    setCurrentPage,
    user
}) => {
    const [quantities, setQuantities] = useState({});

    const handleQuantityChange = (productId, newQuantity) => {
        if (newQuantity > 0) {
            updateCartQuantity(productId, newQuantity);
            setQuantities(prev => ({ ...prev, [productId]: newQuantity }));
        }
    };

    const handleRemove = (productId) => {
        removeFromCart(productId);
    };

    const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const tax = subtotal * 0.18;
    const shipping = subtotal > 500 ? 0 : 40;
    const total = subtotal + tax + shipping;

    if (!cart || cart.length === 0) {
        return (
            <div className="cart-container">
                <div className="empty-cart">
                    <div className="empty-cart-icon">🛒</div>
                    <h2>Your cart is empty</h2>
                    <p>Add items to get started</p>
                    <button 
                        className="continue-shopping-btn"
                        onClick={() => setCurrentPage('products')}
                    >
                        Continue Shopping
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="cart-container">
            <div className="cart-content">
                {/* Cart Items Section */}
                <div className="cart-items-section">
                    <h1>Shopping Cart ({cart.length})</h1>
                    <div className="cart-items">
                        {cart.map(item => (
                            <div key={item.productId} className="cart-item">
                                <img 
                                    src={item.image || 'https://via.placeholder.com/100'} 
                                    alt={item.name}
                                    className="item-image"
                                />
                                <div className="item-details">
                                    <h3>{item.name}</h3>
                                    <p className="item-category">{item.category}</p>
                                    <div className="item-rating">
                                        <span className="stars">★★★★☆</span>
                                        <span className="rating-count">(234)</span>
                                    </div>
                                </div>

                                <div className="quantity-selector">
                                    <button 
                                        onClick={() => handleQuantityChange(item.productId, item.quantity - 1)}
                                        className="qty-btn"
                                    >
                                        −
                                    </button>
                                    <span className="qty-value">{item.quantity}</span>
                                    <button 
                                        onClick={() => handleQuantityChange(item.productId, item.quantity + 1)}
                                        className="qty-btn"
                                    >
                                        +
                                    </button>
                                </div>

                                <div className="item-price">
                                    <span className="current-price">₹{item.price}</span>
                                    <span className="original-price">₹{Math.round(item.price * 1.3)}</span>
                                    <span className="discount">-23%</span>
                                </div>

                                <button 
                                    className="remove-btn"
                                    onClick={() => handleRemove(item.productId)}
                                    title="Remove item"
                                >
                                    🗑️
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Price Summary Section */}
                <div className="price-summary-section">
                    <div className="price-summary">
                        <h2>Price Details</h2>

                        <div className="summary-row">
                            <span>Price ({cart.length} items)</span>
                            <span>₹{subtotal.toFixed(2)}</span>
                        </div>

                        <div className="summary-row">
                            <span>Discount</span>
                            <span className="discount-text">− ₹{(subtotal * 0.23).toFixed(2)}</span>
                        </div>

                        <div className="summary-row">
                            <span>Tax (18% GST)</span>
                            <span>₹{tax.toFixed(2)}</span>
                        </div>

                        <div className="summary-row">
                            <span>Delivery Charges</span>
                            <span className={shipping === 0 ? 'free-shipping' : ''}>
                                {shipping === 0 ? 'Free' : `₹${shipping}`}
                            </span>
                        </div>

                        <div className="summary-divider"></div>

                        <div className="summary-row total">
                            <span>Total Amount</span>
                            <span>₹{total.toFixed(2)}</span>
                        </div>

                        {shipping === 0 && (
                            <div className="free-shipping-msg">
                                ✓ Free Delivery on this order
                            </div>
                        )}

                        <button 
                            className="checkout-btn"
                            onClick={() => setCurrentPage('checkout')}
                        >
                            Proceed to Checkout
                        </button>

                        <button 
                            className="continue-shopping-link"
                            onClick={() => setCurrentPage('products')}
                        >
                            Continue Shopping
                        </button>
                    </div>

                    {/* Safe Checkout Badge */}
                    <div className="safe-checkout">
                        <div className="badge-item">
                            <span className="badge-icon">🔒</span>
                            <span>Safe & Secure</span>
                        </div>
                        <div className="badge-item">
                            <span className="badge-icon">↩️</span>
                            <span>Easy Returns</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default CartPage;
